import { Router, Request, Response, NextFunction } from 'express';
import bcrypt from 'bcrypt';
import jwt from 'jsonwebtoken';
import db from '../database';
import type { LoginRequest, LoginResponse, User, ApiError } from '../types';

const router = Router();

// JWT 密钥配置
const JWT_SECRET = process.env.JWT_SECRET || 'your-secret-key-change-in-production';
const JWT_EXPIRES_IN = '24h';

/**
 * POST /api/auth/login
 * 用户登录
 */
router.post('/login', async (req: Request, res: Response) => {
  try {
    const { username, password }: LoginRequest = req.body;

    // 输入验证
    if (!username || !password) {
      const error: ApiError = {
        code: 400,
        message: '用户名和密码不能为空',
        details: 'Username and password are required',
        timestamp: new Date().toISOString(),
        path: req.path
      };
      return res.status(400).json(error);
    }

    if (username.length < 2 || username.length > 50) {
      const error: ApiError = {
        code: 400,
        message: '用户名长度必须在 2-50 个字符之间',
        details: 'Username must be between 2 and 50 characters',
        timestamp: new Date().toISOString(),
        path: req.path
      };
      return res.status(400).json(error);
    }

    if (password.length < 6 || password.length > 128) {
      const error: ApiError = {
        code: 400,
        message: '密码长度必须在 6-128 个字符之间',
        details: 'Password must be between 6 and 128 characters',
        timestamp: new Date().toISOString(),
        path: req.path
      };
      return res.status(400).json(error);
    }

    // 查询用户
    const user = db.prepare(`
      SELECT id, username, email, password, avatar, phone, role, createdAt
      FROM users
      WHERE username = ?
    `).get(username) as {
      id: number;
      username: string;
      email: string;
      password: string;
      avatar: string | null;
      phone: string | null;
      role: 'user' | 'admin';
      createdAt: string;
    } | undefined;

    if (!user) {
      const error: ApiError = {
        code: 401,
        message: '用户名或密码错误',
        details: 'Invalid username or password',
        timestamp: new Date().toISOString(),
        path: req.path
      };
      return res.status(401).json(error);
    }

    // 验证密码
    const isPasswordValid = await bcrypt.compare(password, user.password);
    if (!isPasswordValid) {
      const error: ApiError = {
        code: 401,
        message: '用户名或密码错误',
        details: 'Invalid username or password',
        timestamp: new Date().toISOString(),
        path: req.path
      };
      return res.status(401).json(error);
    }

    // 生成 JWT token
    const token = jwt.sign(
      {
        userId: user.id,
        username: user.username,
        role: user.role
      },
      JWT_SECRET,
      { expiresIn: JWT_EXPIRES_IN }
    );

    // 构建用户响应（不含密码）
    const userResponse: User = {
      id: user.id,
      username: user.username,
      email: user.email,
      avatar: user.avatar,
      phone: user.phone,
      role: user.role,
      createdAt: user.createdAt
    };

    // 返回登录响应
    const response: LoginResponse = {
      token,
      user: userResponse
    };

    return res.status(200).json(response);
  } catch (error) {
    console.error('Login error:', error);
    const apiError: ApiError = {
      code: 500,
      message: '服务器内部错误',
      details: error instanceof Error ? error.message : 'Unknown error',
      timestamp: new Date().toISOString(),
      path: req.path
    };
    return res.status(500).json(apiError);
  }
});

/**
 * POST /api/auth/register
 * 用户注册（可选功能）
 */
router.post('/register', async (req: Request, res: Response) => {
  try {
    const { username, password, email, phone }: {
      username: string;
      password: string;
      email?: string;
      phone?: string;
    } = req.body;

    // 输入验证
    if (!username || !password) {
      const error: ApiError = {
        code: 400,
        message: '用户名和密码不能为空',
        details: 'Username and password are required',
        timestamp: new Date().toISOString(),
        path: req.path
      };
      return res.status(400).json(error);
    }

    if (username.length < 2 || username.length > 50) {
      const error: ApiError = {
        code: 400,
        message: '用户名长度必须在 2-50 个字符之间',
        details: 'Username must be between 2 and 50 characters',
        timestamp: new Date().toISOString(),
        path: req.path
      };
      return res.status(400).json(error);
    }

    if (password.length < 6 || password.length > 128) {
      const error: ApiError = {
        code: 400,
        message: '密码长度必须在 6-128 个字符之间',
        details: 'Password must be between 6 and 128 characters',
        timestamp: new Date().toISOString(),
        path: req.path
      };
      return res.status(400).json(error);
    }

    // 检查用户名是否已存在
    const existingUser = db.prepare('SELECT id FROM users WHERE username = ?').get(username);
    if (existingUser) {
      const error: ApiError = {
        code: 409,
        message: '用户名已存在',
        details: 'Username already exists',
        timestamp: new Date().toISOString(),
        path: req.path
      };
      return res.status(409).json(error);
    }

    // 哈希密码
    const hashedPassword = await bcrypt.hash(password, 10);
    const createdAt = new Date().toISOString();

    // 插入新用户
    const result = db.prepare(`
      INSERT INTO users (username, password, email, phone, role, createdAt)
      VALUES (?, ?, ?, ?, 'user', ?)
    `).run(username, hashedPassword, email || null, phone || null, createdAt);

    // 查询创建的用户
    const newUser = db.prepare(`
      SELECT id, username, email, avatar, phone, role, createdAt
      FROM users
      WHERE id = ?
    `).get(result.lastInsertRowid) as User;

    // 生成 JWT token
    const token = jwt.sign(
      {
        userId: newUser.id,
        username: newUser.username,
        role: newUser.role
      },
      JWT_SECRET,
      { expiresIn: JWT_EXPIRES_IN }
    );

    const response: LoginResponse = {
      token,
      user: newUser
    };

    return res.status(201).json(response);
  } catch (error) {
    console.error('Register error:', error);
    const apiError: ApiError = {
      code: 500,
      message: '服务器内部错误',
      details: error instanceof Error ? error.message : 'Unknown error',
      timestamp: new Date().toISOString(),
      path: req.path
    };
    return res.status(500).json(apiError);
  }
});

/**
 * GET /api/auth/me
 * 获取当前用户信息（需要认证）
 */
router.get('/me', (req: Request, res: Response) => {
  try {
    // 从 Authorization header 获取 token
    const authHeader = req.headers.authorization;
    if (!authHeader || !authHeader.startsWith('Bearer ')) {
      const error: ApiError = {
        code: 401,
        message: '未授权，请先登录',
        details: 'Authorization header is required',
        timestamp: new Date().toISOString(),
        path: req.path
      };
      return res.status(401).json(error);
    }

    const token = authHeader.substring(7);

    // 验证 token
    const decoded = jwt.verify(token, JWT_SECRET) as {
      userId: number;
      username: string;
      role: string;
    };

    // 查询用户信息
    const user = db.prepare(`
      SELECT id, username, email, avatar, phone, role, createdAt
      FROM users
      WHERE id = ?
    `).get(decoded.userId) as User | undefined;

    if (!user) {
      const error: ApiError = {
        code: 404,
        message: '用户不存在',
        details: 'User not found',
        timestamp: new Date().toISOString(),
        path: req.path
      };
      return res.status(404).json(error);
    }

    return res.status(200).json(user);
  } catch (error) {
    if (error instanceof jwt.JsonWebTokenError) {
      const apiError: ApiError = {
        code: 401,
        message: '无效的 token',
        details: 'Invalid token',
        timestamp: new Date().toISOString(),
        path: req.path
      };
      return res.status(401).json(apiError);
    }

    console.error('Get user error:', error);
    const apiError: ApiError = {
      code: 500,
      message: '服务器内部错误',
      details: error instanceof Error ? error.message : 'Unknown error',
      timestamp: new Date().toISOString(),
      path: req.path
    };
    return res.status(500).json(apiError);
  }
});

export default router;

import { Router, Request, Response } from 'express';
import type { Product, PaginatedProducts, GetProductsQueryParams, GetProductByIdPathParams, ApiError } from '../types';

const router = Router();

/**
 * GET /api/products
 * 获取商品列表（支持分页、筛选、排序）
 */
router.get('/', (req: Request, res: Response) => {
  try {
    const query = req.query as unknown as GetProductsQueryParams;

    // 解析分页参数
    let page = parseInt(query.page as unknown as string) || 1;
    let pageSize = parseInt(query.pageSize as unknown as string) || 10;

    // 参数边界检查
    if (page < 1) page = 1;
    if (pageSize < 1) pageSize = 1;
    if (pageSize > 100) pageSize = 100;

    const offset = (page - 1) * pageSize;

    // 解析筛选参数
    const category = query.category || '';
    const keyword = query.keyword || '';

    // 解析排序参数
    const validSortFields = ['price', 'createdAt', 'name', 'sales'];
    const sortBy = validSortFields.includes(query.sortBy as string) ? query.sortBy : 'createdAt';
    const sortOrder = query.sortOrder === 'asc' ? 'ASC' : 'DESC';

    // 构建 WHERE 条件
    const conditions: string[] = ["status = 'on_sale'"];
    const params: (string | number)[] = [];

    if (category) {
      conditions.push('category = ?');
      params.push(category);
    }

    if (keyword) {
      conditions.push('(name LIKE ? OR description LIKE ?)');
      const keywordPattern = `%${keyword}%`;
      params.push(keywordPattern, keywordPattern);
    }

    const whereClause = conditions.length > 0 ? `WHERE ${conditions.join(' AND ')}` : '';

    // 查询总数
    const countResult = db.prepare(`
      SELECT COUNT(*) as total
      FROM products
      ${whereClause}
    `).get(...params) as { total: number };

    const total = countResult.total;
    const totalPages = Math.ceil(total / pageSize);

    // 查询商品列表
    const sortColumn = sortBy === 'name' ? 'name' : sortBy;
    const products = db.prepare(`
      SELECT id, name, description, price, originalPrice, imageUrl, category, 
             sales, stock, status, rating, createdAt, updatedAt
      FROM products
      ${whereClause}
      ORDER BY ${sortColumn} ${sortOrder}
      LIMIT ? OFFSET ?
    `).all(...params, pageSize, offset) as Product[];

    const response: PaginatedProducts = {
      data: products,
      total,
      page,
      pageSize,
      totalPages
    };

    return res.status(200).json(response);
  } catch (error) {
    console.error('Get products error:', error);
    const apiError: ApiError = {
      code: 500,
      message: '服务器内部错误',
      details: error instanceof Error ? error.message : 'Unknown error',
      timestamp: new Date().toISOString(),
      path: req.path
    };
    return res.status(500).json(apiError);
  }
});

/**
 * GET /api/products/:id
 * 获取商品详情
 */
router.get('/:id', (req: Request, res: Response) => {
  try {
    const { id } = req.params as unknown as GetProductByIdPathParams;

    // 验证 ID
    if (!id || isNaN(id)) {
      const error: ApiError = {
        code: 400,
        message: '无效的商品 ID',
        details: 'Invalid product ID',
        timestamp: new Date().toISOString(),
        path: req.path
      };
      return res.status(400).json(error);
    }

    const product = db.prepare(`
      SELECT id, name, description, price, originalPrice, imageUrl, category,
             sales, stock, status, rating, createdAt, updatedAt
      FROM products
      WHERE id = ? AND status != 'deleted'
    `).get(id) as Product | undefined;

    if (!product) {
      const error: ApiError = {
        code: 404,
        message: '商品不存在或已下架',
        details: 'Product not found or has been removed',
        timestamp: new Date().toISOString(),
        path: req.path
      };
      return res.status(404).json(error);
    }

    return res.status(200).json(product);
  } catch (error) {
    console.error('Get product by ID error:', error);
    const apiError: ApiError = {
      code: 500,
      message: '服务器内部错误',
      details: error instanceof Error ? error.message : 'Unknown error',
      timestamp: new Date().toISOString(),
      path: req.path
    };
    return res.status(500).json(apiError);
  }
});

/**
 * GET /api/products/categories
 * 获取商品分类列表
 */
router.get('/meta/categories', (req: Request, res: Response) => {
  try {
    const categories = db.prepare(`
      SELECT DISTINCT category, COUNT(*) as productCount
      FROM products
      WHERE status = 'on_sale'
      GROUP BY category
      ORDER BY category
    `).all() as { category: string; productCount: number }[];

    return res.status(200).json({
      data: categories,
      total: categories.length
    });
  } catch (error) {
    console.error('Get categories error:', error);
    const apiError: ApiError = {
      code: 500,
      message: '服务器内部错误',
      details: error instanceof Error ? error.message : 'Unknown error',
      timestamp: new Date().toISOString(),
      path: req.path
    };
    return res.status(500).json(apiError);
  }
});

/**
 * GET /api/products/featured
 * 获取精选商品
 */
router.get('/meta/featured', (req: Request, res: Response) => {
  try {
    const limit = parseInt(req.query.limit as string) || 8;

    const products = db.prepare(`
      SELECT id, name, description, price, originalPrice, imageUrl, category,
             sales, stock, status, rating, createdAt, updatedAt
      FROM products
      WHERE status = 'on_sale' AND rating >= 4.0
      ORDER BY rating DESC, sales DESC
      LIMIT ?
    `).all(limit) as Product[];

    return res.status(200).json({
      data: products,
      total: products.length
    });
  } catch (error) {
    console.error('Get featured products error:', error);
    const apiError: ApiError = {
      code: 500,
      message: '服务器内部错误',
      details: error instanceof Error ? error.message : 'Unknown error',
      timestamp: new Date().toISOString(),
      path: req.path
    };
    return res.status(500).json(apiError);
  }
});

export default router;

// 导入数据库实例（这里使用占位符，实际项目中需要从 database 模块导入）
import db from '../database';

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';
import './index.css';

// Mount the React application to the DOM
ReactDOM.createRoot(document.getElementById('root')!).render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import { useState, useEffect } from 'react';
import type { User, Product, LoginRequest, LoginResponse } from './types';
import { apiClient } from './mocks/api';

function App() {
  // State management
  const [isLoggedIn, setIsLoggedIn] = useState<boolean>(false);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [products, setProducts] = useState<Product[]>([]);
  const [isLoading, setIsLoading] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);

  // Login form state
  const [username, setUsername] = useState<string>('');
  const [password, setPassword] = useState<string>('');

  // Fetch products on component mount
  useEffect(() => {
    fetchProducts();
  }, []);

  // Fetch products from API
  const fetchProducts = async () => {
    setIsLoading(true);
    setError(null);
    try {
      const response = await apiClient.getProducts();
      setProducts(response.data);
    } catch (err) {
      setError('Failed to fetch products. Please try again later.');
      console.error('Error fetching products:', err);
    } finally {
      setIsLoading(false);
    }
  };

  // Handle user login
  const handleLogin = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    setError(null);

    // Validate input
    if (!username || !password) {
      setError('Please enter both username and password.');
      return;
    }

    if (username.length < 2 || username.length > 50) {
      setError('Username must be between 2 and 50 characters.');
      return;
    }

    if (password.length < 6 || password.length > 128) {
      setError('Password must be between 6 and 128 characters.');
      return;
    }

    setIsLoading(true);

    try {
      const loginData: LoginRequest = { username, password };
      const response: LoginResponse = await apiClient.login(loginData);
      setCurrentUser(response.user);
      setIsLoggedIn(true);
      setUsername('');
      setPassword('');
    } catch (err) {
      setError('Invalid username or password. Please try again.');
      console.error('Login error:', err);
    } finally {
      setIsLoading(false);
    }
  };

  // Handle user logout
  const handleLogout = () => {
    setCurrentUser(null);
    setIsLoggedIn(false);
  };

  // Render login form
  const renderLoginForm = () => (
    <div className="login-container">
      <div className="login-card">
        <h1>Welcome to E-Commerce Platform</h1>
        <h2>Login</h2>
        <form onSubmit={handleLogin} className="login-form">
          <div className="form-group">
            <label htmlFor="username">Username</label>
            <input
              type="text"
              id="username"
              value={username}
              onChange={(e) => setUsername(e.target.value)}
              placeholder="Enter your username"
              disabled={isLoading}
              autoComplete="username"
            />
          </div>
          <div className="form-group">
            <label htmlFor="password">Password</label>
            <input
              type="password"
              id="password"
              value={password}
              onChange={(e) => setPassword(e.target.value)}
              placeholder="Enter your password"
              disabled={isLoading}
              autoComplete="current-password"
            />
          </div>
          {error && <div className="error-message">{error}</div>}
          <button type="submit" className="btn-primary" disabled={isLoading}>
            {isLoading ? 'Logging in...' : 'Login'}
          </button>
        </form>
      </div>
    </div>
  );

  // Render product grid
  const renderProductGrid = () => (
    <div className="products-container">
      <header className="header">
        <h1>E-Commerce Platform</h1>
        <div className="user-info">
          {currentUser && (
            <>
              <span>Welcome, {currentUser.username}!</span>
              <span className="user-email">{currentUser.email}</span>
            </>
          )}
          <button onClick={handleLogout} className="btn-secondary">
            Logout
          </button>
        </div>
      </header>

      <main className="main-content">
        <section className="products-section">
          <h2>Featured Products</h2>
          {isLoading ? (
            <div className="loading">Loading products...</div>
          ) : error ? (
            <div className="error-message">{error}</div>
          ) : products.length === 0 ? (
            <div className="empty-state">No products available.</div>
          ) : (
            <div className="products-grid">
              {products.map((product) => (
                <article key={product.id} className="product-card">
                  <div className="product-image">
                    {product.imageUrl ? (
                      <img src={product.imageUrl} alt={product.name} />
                    ) : (
                      <div className="placeholder-image">No Image</div>
                    )}
                  </div>
                  <div className="product-info">
                    <h3 className="product-name">{product.name}</h3>
                    <p className="product-description">
                      {product.description || 'No description available.'}
                    </p>
                    <div className="product-meta">
                      <span className="product-category">{product.category}</span>
                      {product.rating && (
                        <span className="product-rating">★ {product.rating.toFixed(1)}</span>
                      )}
                    </div>
                    <div className="product-pricing">
                      <span className="product-price">¥{product.price.toFixed(2)}</span>
                      {product.originalPrice && (
                        <span className="product-original-price">
                          ¥{product.originalPrice.toFixed(2)}
                        </span>
                      )}
                    </div>
                    <div className="product-footer">
                      <span className="product-stock">
                        {product.stock > 0 ? `${product.stock} in stock` : 'Out of stock'}
                      </span>
                      {product.sales !== undefined && (
                        <span className="product-sales">{product.sales} sold</span>
                      )}
                    </div>
                  </div>
                </article>
              ))}
            </div>
          )}
        </section>
      </main>

      <footer className="footer">
        <p>&copy; 2024 E-Commerce Platform. All rights reserved.</p>
      </footer>
    </div>
  );

  // Render the appropriate view based on login state
  return isLoggedIn ? renderProductGrid() : renderLoginForm();
}

export default App;

import React, { useEffect, useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import type { Product, PaginatedProducts } from '../types';
import { apiClient } from '../mocks/api';

/**
 * 首页组件
 * 电商平台的入口页面，展示精选商品和平台概览
 */
const Home: React.FC = () => {
  const navigate = useNavigate();
  const [featuredProducts, setFeaturedProducts] = useState<Product[]>([]);
  const [isLoading, setIsLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    loadFeaturedProducts();
  }, []);

  const loadFeaturedProducts = async () => {
    try {
      setIsLoading(true);
      setError(null);
      const response: PaginatedProducts = await apiClient.getProducts({
        pageSize: 8,
        sortBy: 'sales',
        sortOrder: 'desc'
      });
      setFeaturedProducts(response.data);
    } catch (err) {
      setError(err instanceof Error ? err.message : '加载商品失败');
    } finally {
      setIsLoading(false);
    }
  };

  const handleProductClick = (productId: number) => {
    navigate(`/products/${productId}`);
  };

  const handleShopNow = () => {
    navigate('/products');
  };

  return (
    <div className="min-h-screen bg-gray-50">
      {/* 导航栏 */}
      <nav className="bg-white shadow-sm">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex justify-between items-center h-16">
            <div className="flex items-center">
              <h1 className="text-2xl font-bold text-indigo-600">电商平台</h1>
            </div>
            <div className="flex items-center space-x-4">
              <Link
                to="/products"
                className="text-gray-700 hover:text-indigo-600 px-3 py-2 rounded-md font-medium"
              >
                商品列表
              </Link>
              <Link
                to="/login"
                className="bg-indigo-600 text-white px-4 py-2 rounded-md hover:bg-indigo-700 transition-colors"
              >
                登录
              </Link>
            </div>
          </div>
        </div>
      </nav>

      {/* 横幅区域 */}
      <section className="bg-gradient-to-r from-indigo-600 to-purple-600 text-white">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-24">
          <div className="text-center">
            <h2 className="text-4xl md:text-6xl font-extrabold mb-6">
              欢迎来到优质电商平台
            </h2>
            <p className="text-xl md:text-2xl mb-8 text-indigo-100">
              发现品质好物，享受购物乐趣
            </p>
            <button
              onClick={handleShopNow}
              className="bg-white text-indigo-600 px-8 py-4 rounded-lg text-lg font-semibold hover:bg-gray-100 transition-colors shadow-lg"
