/**
 * 商品列表页组件
 * 展示商品列表，支持筛选、排序、分页功能
 */
const ProductList: React.FC = () => {
  const navigate = useNavigate();

  // 数据状态
  const [products, setProducts] = useState<Product[]>([]);
  const [total, setTotal] = useState<number>(0);

  // 加载状态
  const [isLoading, setIsLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);

  // 查询参数状态
  const [page, setPage] = useState<number>(1);
  const [pageSize, setPageSize] = useState<number>(12);
  const [category, setCategory] = useState<string>('');
  const [keyword, setKeyword] = useState<string>('');
  const [sortBy, setSortBy] = useState<GetProductsQueryParams['sortBy']>('sales');
  const [sortOrder, setSortOrder] = useState<GetProductsQueryParams['sortOrder']>('desc');

  // 搜索输入状态（用于防抖）
  const [searchInput, setSearchInput] = useState<string>('');

  // 计算总页数
  const totalPages = useMemo(() => {
    return Math.ceil(total / pageSize);
  }, [total, pageSize]);

  // 加载商品数据
  const loadProducts = useCallback(async () => {
    try {
      setIsLoading(true);
      setError(null);

      const params: GetProductsQueryParams = {
        page,
        pageSize,
        sortBy,
        sortOrder
      };

      if (category) {
        params.category = category;
      }

      if (keyword.trim()) {
        params.keyword = keyword.trim();
      }

      const response: PaginatedProducts = await apiClient.getProducts(params);
      setProducts(response.data);
      setTotal(response.total);
    } catch (err) {
      setError(err instanceof Error ? err.message : '加载商品失败');
    } finally {
      setIsLoading(false);
    }
  }, [page, pageSize, category, keyword, sortBy, sortOrder]);

  // 初始加载和参数变化时重新加载
  useEffect(() => {
    loadProducts();
  }, [loadProducts]);

  // 处理搜索提交
  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault();
    setKeyword(searchInput);
    setPage(1); // 重置到第一页
  };

  // 处理分类变化
  const handleCategoryChange = (newCategory: string) => {
    setCategory(newCategory);
    setPage(1);
  };

  // 处理排序变化
  const handleSortChange = (value: string) => {
    const [newSortBy, newSortOrder] = value.split('-') as [typeof sortBy, typeof sortOrder];
    setSortBy(newSortBy);
    setSortOrder(newSortOrder);
    setPage(1);
  };

  // 处理每页数量变化
  const handlePageSizeChange = (newPageSize: number) => {
    setPageSize(newPageSize);
    setPage(1);
  };

  // 翻页
  const handlePageChange = (newPage: number) => {
    if (newPage >= 1 && newPage <= totalPages) {
      setPage(newPage);
      // 滚动到顶部
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  };

  // 商品点击
  const handleProductClick = (productId: number) => {
    navigate(`/products/${productId}`);
  };

  // 生成页码数组（带省略号）
  const getPageNumbers = useMemo(() => {
    const pages: (number | string)[] = [];
    const maxVisible = 5;

    if (totalPages <= maxVisible + 2) {
      for (let i = 1; i <= totalPages; i++) {
        pages.push(i);
      }
    } else {
      pages.push(1);

      if (page > 3) {
        pages.push('...');
      }

      const start = Math.max(2, page - 1);
      const end = Math.min(totalPages - 1, page + 1);

      for (let i = start; i <= end; i++) {
        pages.push(i);
      }

      if (page < totalPages - 2) {
        pages.push('...');
      }

      pages.push(totalPages);
    }

    return pages;
  }, [page, totalPages]);

