import express, { Request, Response, NextFunction } from 'express';
import cors from 'cors';
import jwt from 'jsonwebtoken';
import { initDatabase, closeDatabase, userRepository, productRepository, verifyPassword } from './database/db';
import type { 
  LoginRequest, 
  LoginResponse, 
  User, 
  Product, 
  PaginatedProducts,
  GetProductsQueryParams,
  GetProductByIdPathParams,
  ApiError 
} from '../types';

// 配置
const PORT = process.env.PORT || 3001;
const JWT_SECRET = process.env.JWT_SECRET || 'ecommerce-secret-key-change-in-production';
const JWT_EXPIRES_IN = '24h';

// Express 应用
const app = express();

// 中间件
app.use(cors());
app.use(express.json());

// 请求日志中间件
app.use((req: Request, _res: Response, next: NextFunction) => {
