initDatabase();

// ==================== 认证中间件 ====================

interface JwtPayload {
  userId: number;
  username: string;
  role: string;
}

interface AuthenticatedRequest extends Request {
  user?: JwtPayload;
}

/**
 * JWT 认证中间件
 */
function authenticateToken(req: AuthenticatedRequest, res: Response, next: NextFunction): void {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1]; // Bearer TOKEN

  if (!token) {
    const error: ApiError = {
      code: 401,
      message: '未提供认证令牌',
      timestamp: new Date().toISOString(),
      path: req.path
    };
    res.status(401).json(error);
    return;
  }

  try {
    const decoded = jwt.verify(token, JWT_SECRET) as JwtPayload;
    req.user = decoded;
    next();
  } catch (err) {
    const error: ApiError = {
      code: 401,
      message: '无效或过期的令牌',
      timestamp: new Date().toISOString(),
      path: req.path
    };
    res.status(401).json(error);
  }
}

/**
 * 可选认证中间件（不强制要求登录）
 */
function optionalAuth(req: AuthenticatedRequest, _res: Response, next: NextFunction): void {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];

  if (token) {
    try {
      const decoded = jwt.verify(token, JWT_SECRET) as JwtPayload;
      req.user = decoded;
    } catch {
      // 忽略无效令牌
    }
  }
  next();
}

// ==================== 认证接口 ====================

/**
 * POST /api/auth/login
 * 用户登录
 */
app.post('/api/auth/login', (req: Request<{}, {}, LoginRequest>, res: Response) => {
  try {
    const { username, password } = req.body;

    // 验证请求参数
    if (!username || !password) {
      const error: ApiError = {
        code: 400,
        message: '用户名和密码不能为空',
        timestamp: new Date().toISOString(),
        path: '/api/auth/login'
      };
      res.status(400).json(error);
      return;
    }

    if (username.length < 2 || username.length > 50) {
      const error: ApiError = {
        code: 400,
        message: '用户名长度必须在2-50个字符之间',
        timestamp: new Date().toISOString(),
        path: '/api/auth/login'
      };
      res.status(400).json(error);
      return;
    }

    if (password.length < 6 || password.length > 128) {
      const error: ApiError = {
        code: 400,
        message: '密码长度必须在6-128个字符之间',
        timestamp: new Date().toISOString(),
        path: '/api/auth/login'
      };
      res.status(400).json(error);
      return;
    }

    // 查找用户
    const user = userRepository.findByUsername(username);
    if (!user) {
      const error: ApiError = {
        code: 401,
        message: '用户名或密码错误',
        timestamp: new Date().toISOString(),
        path: '/api/auth/login'
      };
      res.status(401).json(error);
      return;
    }

    // 验证密码
    // 注意：在实际应用中，密码哈希存储在单独的表中或加密存储
    const db = require('./database/db').getDatabase();
    const passwordRow = db.prepare('SELECT password FROM users WHERE username = ?').get(username) as { password: string };

    if (!passwordRow || !verifyPassword(password, passwordRow.password)) {
      const error: ApiError = {
        code: 401,
        message: '用户名或密码错误',
        timestamp: new Date().toISOString(),
        path: '/api/auth/login'
      };
      res.status(401).json(error);
      return;
    }

    // 生成 JWT 令牌
    const payload: JwtPayload = {
      userId: user.id,
      username: user.username,
      role: user.role || 'user'
    };

    const token = jwt.sign(payload, JWT_SECRET, { expiresIn: JWT_EXPIRES_IN });

    const response: LoginResponse = {
      token,
      user: {
        id: user.id,
        username: user.username,
        email: user.email,
        avatar: user.avatar,
        phone: user.phone,
        role: user.role,
        createdAt: user.createdAt
      }
    };

    console.log(`[${new Date().toISOString()}] User logged in: ${username}`);
    res.json(response);
  } catch (err) {
    console.error('Login error:', err);
    const error: ApiError = {
      code: 500,
      message: '服务器内部错误',
      details: err instanceof Error ? err.message : undefined,
      timestamp: new Date().toISOString(),
      path: '/api/auth/login'
    };
    res.status(500).json(error);
  }
});

/**
 * GET /api/auth/me
 * 获取当前用户信息
 */
app.get('/api/auth/me', authenticateToken, (req: AuthenticatedRequest, res: Response) => {
  try {
    const user = userRepository.findById(req.user!.userId);
    if (!user) {
      const error: ApiError = {
        code: 404,
        message: '用户不存在',
        timestamp: new Date().toISOString(),
        path: '/api/auth/me'
      };
      res.status(404).json(error);
      return;
    }

    res.json(user);
  } catch (err) {
    console.error('Get user error:', err);
    const error: ApiError = {
      code: 500,
      message: '服务器内部错误',
      timestamp: new Date().toISOString(),
      path: '/api/auth/me'
    };
    res.status(500).json(error);
  }
});

// ==================== 商品接口 ====================

/**
 * GET /api/products
 * 获取商品列表（支持分页、筛选、搜索、排序）
 */
app.get('/api/products', optionalAuth, (req: Request<{}, {}, {}, GetProductsQueryParams>, res: Response) => {
  try {
    const {
      page = 1,
      pageSize = 10,
      category,
      keyword,
      sortBy,
      sortOrder
    } = req.query;

    // 验证分页参数
    const pageNum = Math.max(1, parseInt(String(page), 10) || 1);
    const pageSizeNum = Math.min(100, Math.max(1, parseInt(String(pageSize), 10) || 10));

    // 验证排序参数
    const validSortFields = ['price', 'createdAt', 'name', 'sales'];
    const sortField = sortBy && validSortFields.includes(sortBy) ? sortBy : 'createdAt';
    const sortDirection = sortOrder === 'asc' ? 'asc' : 'desc';

    const result = productRepository.findAll({
      page: pageNum,
      pageSize: pageSizeNum,
      category,
      keyword,
      sortBy: sortField as 'price' | 'createdAt' | 'name' | 'sales',
      sortOrder: sortDirection as 'asc' | 'desc'
    });

    const response: PaginatedProducts = {
      data: result.data,
      total: result.total,
      page: pageNum,
      pageSize: pageSizeNum,
      totalPages: Math.ceil(result.total / pageSizeNum)
    };

    res.json(response);
  } catch (err) {
    console.error('Get products error:', err);
    const error: ApiError = {
      code: 500,
      message: '服务器内部错误',
      timestamp: new Date().toISOString(),
      path: '/api/products'
    };
    res.status(500).json(error);
  }
});

