/**
 * 简单的密码哈希函数（生产环境应使用bcrypt）
 * @param password 明文密码
 * @returns 哈希后的密码
 */
function hashPassword(password: string): string {
  // 简单哈希，生产环境请使用 bcrypt
  const crypto = require('crypto');
  return crypto.createHash('sha256').update(password).digest('hex');
}

/**
 * 验证密码
 * @param password 明文密码
 * @param hash 哈希后的密码
 * @returns 是否匹配
 */
export function verifyPassword(password: string, hash: string): boolean {
  return hashPassword(password) === hash;
}

/**
 * 关闭数据库连接
 */
export function closeDatabase(): void {
  if (db) {
    db.close();
    db = null;
  }
}

// 用户相关操作
export const userRepository = {
  findByUsername(username: string): User | undefined {
    const db = getDatabase();
    const row = db.prepare(`
      SELECT id, username, email, avatar, phone, role, createdAt
      FROM users
      WHERE username = ?
    `).get(username) as any;
    return row;
  },

  findById(id: number): User | undefined {
    const db = getDatabase();
    const row = db.prepare(`
      SELECT id, username, email, avatar, phone, role, createdAt
      FROM users
      WHERE id = ?
    `).get(id) as any;
    return row;
  }
};

// 商品相关操作
export const productRepository = {
  findAll(options: {
    page?: number;
    pageSize?: number;
    category?: string;
    keyword?: string;
    sortBy?: 'price' | 'createdAt' | 'name' | 'sales';
    sortOrder?: 'asc' | 'desc';
  }): { data: Product[]; total: number } {
    const db = getDatabase();
    const { page = 1, pageSize = 10, category, keyword, sortBy = 'createdAt', sortOrder = 'desc' } = options;

    let whereClause = "WHERE status = 'on_sale'";
    const params: any[] = [];

    if (category) {
      whereClause += " AND category = ?";
      params.push(category);
    }

    if (keyword) {
      whereClause += " AND (name LIKE ? OR description LIKE ?)";
      params.push(`%${keyword}%`, `%${keyword}%`);
    }

    // 获取总数
    const countResult = db.prepare(`SELECT COUNT(*) as total FROM products ${whereClause}`).get(...params) as { total: number };
    const total = countResult.total;

    // 验证排序字段
    const validSortFields = ['price', 'createdAt', 'name', 'sales'];
    const sortField = validSortFields.includes(sortBy) ? sortBy : 'createdAt';
    const sortDirection = sortOrder === 'asc' ? 'ASC' : 'DESC';

    // 获取分页数据
    const offset = (page - 1) * pageSize;
    const data = db.prepare(`
      SELECT * FROM products
      ${whereClause}
      ORDER BY ${sortField} ${sortDirection}
      LIMIT ? OFFSET ?
    `).all(...params, pageSize, offset) as Product[];

    return { data, total };
  },

  findById(id: number): Product | undefined {
    const db = getDatabase();
    return db.prepare('SELECT * FROM products WHERE id = ? AND status != ?').get(id, 'deleted') as Product | undefined;
  },

  getCategories(): string[] {
    const db = getDatabase();
    const rows = db.prepare('SELECT DISTINCT category FROM products WHERE status = ?').all('on_sale') as { category: string }[];
    return rows.map(row => row.category);
  }
};

export default {
  initDatabase,
  getDatabase,
  closeDatabase,
  userRepository,
  productRepository
};

